const PROM = 'http://monitoring-kube-prometheus-prometheus.monitoring.svc.cluster.local:9090/api/v1/query';

const q = async (query) => {
  const r = await $http.get({ url: PROM, qs: { query } });
  const res = r.data.data.result;
  return res.length > 0 ? parseFloat(res[0].value[1]) : 0;
};

const qAll = async (query) => {
  const r = await $http.get({ url: PROM, qs: { query } });
  return r.data.data.result;
};

// 오퍼레이터 업 상태
const upResult    = await qAll('up{job=~"operator-kafka.*"}');
const operatorUp  = upResult.filter(r => r.value[1] === '1').length;
const operatorTotal = upResult.length;

// Kafka 클러스터 상태 (1 = Ready, 0 = NotReady)
const clusterStateResult = await qAll('strimzi_resource_state{kind="Kafka"}');
const totalClusters   = clusterStateResult.length;
const healthyClusters = clusterStateResult.filter(r => r.value[1] === '1').length;
const unhealthyClusters = totalClusters - healthyClusters;

// 재조정 지표
const reconSuccess = await q('sum(strimzi_reconciliations_successful_total) or vector(0)');
const reconFailed  = await q('sum(strimzi_reconciliations_failed_total) or vector(0)');
const reconTotal   = await q('sum(strimzi_reconciliations_total) or vector(0)');

// 1시간 신규 재조정 실패
const newReconFail = await q('sum(increase(strimzi_reconciliations_failed_total[1h])) or vector(0)');

// 관리 중인 리소스 수 (kind=Kafka만)
const kafkaResources = await q('sum(strimzi_resources{kind="Kafka"}) or vector(0)');

// 인증서 만료 최솟값 (ms → days)
const certResult  = await qAll('strimzi_certificate_expiration_timestamp_ms');
const now         = Date.now();
const certMinDays = certResult.length > 0
  ? Math.min(...certResult.map(r => (parseFloat(r.value[1]) - now) / 86400000))
  : null;

const alerts = [];
if (operatorUp < operatorTotal)  alerts.push(`🔴 오퍼레이터 Pod ${operatorTotal - operatorUp}개 다운`);
if (unhealthyClusters > 0)       alerts.push(`🔴 Kafka 클러스터 ${unhealthyClusters}개 비정상`);
if (newReconFail > 0)            alerts.push(`⚠️ 최근 1h 재조정 실패: ${newReconFail}건`);
if (certMinDays !== null && certMinDays < 30) alerts.push(`⚠️ 인증서 만료 임박: ${Math.floor(certMinDays)}일 남음`);

const status = (operatorUp < operatorTotal || unhealthyClusters > 0) ? 'error'
             : newReconFail > 0 ? 'warning'
             : 'ok';

return [{ json: {
  service: 'Strimzi Kafka Operator',
  status,
  metrics: { operatorUp, operatorTotal, totalClusters, healthyClusters, unhealthyClusters, reconSuccess, reconFailed, newReconFail, kafkaResources, certMinDays: certMinDays !== null ? Math.floor(certMinDays) : 'N/A' },
  alerts
}}];
